using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        List<string> players = new List<string>();

        players.Add("Alex");
        players.Add("Mia");
        players.Add("John");
        players.Add("Sara");
        players.Add("Leo");

        Console.WriteLine("First player: " + players[0]);
        Console.WriteLine("Fourth player: " + players[3]);
        Console.WriteLine("Players count: " + players.Count);

        players.Add("Emma");

        Console.WriteLine("Players count after adding: " + players.Count);
        Console.WriteLine("New player: " + players[5]);
    }
}

using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        List<string> products = new List<string>();

        products.Add("Bread");
        products.Add("Milk");
        products.Add("Cheese");
        products.Add("Apple");

        Console.WriteLine("First product: " + products[0]);
        Console.WriteLine("Third product: " + products[2]);
        Console.WriteLine("Products count: " + products.Count);

        products.Add("Juice");

        Console.WriteLine("Updated products count: " + products.Count);
    }
}
